mapper.insert:
		INSERT 
		  INTO MA3_OPEN_BANK_API_LOG (
		      TRAD_DATE
    		, USER_ID
    		, USER_CIF_NO
    		, TRAD_CLS
    		, BANK_TRAD_ID
    		, API_TRAD_ID
    		, TRAD_SEQ
    		, CHNL_GB
    		, API_URL
    		, DATA
    		, REGISTTIME
    		, API_DETAIL_CLS
    		, RES_CODE
    		, BANK_RSP_CODE
		) VALUES (
		 	  VARCHAR_FORMAT(CURRENT TIMESTAMP, 'YYYYMMDD')
			, #{userId}
			, #{userCifNo}
			, #{tradCls}
			, #{bankTradId}
			, #{apiTradId}
			, #{tradSeq}
			, #{chnlGb}
			, #{apiUrl}
			, #{data}
			, CURRENT TIMESTAMP
			, #{apiDetailCls}
			, #{resCode}
			, #{bankRspCode}
		)
